import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, tap, catchError, of } from 'rxjs';


interface RegisterUser {
  name: string;
  email: string;
  login: string;
  password: string;
}

interface LoginUser {
  email: string;
  password: string;
}

@Injectable({
  providedIn: 'root',
})
export class AuthService {
  private tokenKey = 'auth_token';
  private userKey = 'user_name';

  private apiUrl = 'https://characters.discloud.app/api/user';
  private loginUrl = 'https://characters.discloud.app/login'; // Confirma se esse é o endpoint correto

  constructor(private http: HttpClient) {}

  // ✅ Registrar um novo usuário
  registerUser(userData: RegisterUser): Observable<any> {
    return this.http.post(this.apiUrl, userData, {
      headers: { 'Content-Type': 'application/json' },
    });
  }

  // ✅ Login do usuário
  loginUser(userData: LoginUser): Observable<any> {
    return this.http.post(this.loginUrl, userData, {
      headers: { 'Content-Type': 'application/json' },
    }).pipe(
      tap((response: any) => {
        if (response.token && response.user) {
          localStorage.setItem(this.tokenKey, response.token);
          localStorage.setItem(this.userKey, response.user.name);
          localStorage.setItem('user_email', response.user.email);

          // Salvar o status de verificação do email e a mensagem
          if (response.hasOwnProperty('emailVerified')) {
            localStorage.setItem('email_verified', String(response.emailVerified));
          }
          if (response.verificationMessage) {
            localStorage.setItem('verification_message', response.verificationMessage);
          }
        }
      })
    );
  }

   // ✅ Verificação de email
   getUserVerificationStatus(): Observable<any> {
    // Se tivermos os dados no localStorage, vamos usá-los em vez de chamar a API
    const emailVerified = localStorage.getItem('email_verified') === 'true';
    const verificationMessage = localStorage.getItem('verification_message');

    // Se já temos os dados salvos do login, usamos eles
    if (verificationMessage) {
      return new Observable(observer => {
        observer.next({
          emailVerified: emailVerified,
          verificationMessage: verificationMessage
        });
        observer.complete();
      });
    }

    // Caso contrário, tentamos buscar do servidor
    const token = localStorage.getItem(this.tokenKey);
    if (!token) return new Observable(observer => observer.next(null));

    return this.http.get('https://characters.discloud.app/api/user', {
      headers: { Authorization: `Bearer ${token}` }
    }).pipe(
      // Tratamento de erro para evitar que a aplicação quebre se o servidor falhar
      catchError(error => {
        console.error('Erro ao verificar status do email:', error);
        return of({
          emailVerified: false,
          verificationMessage: 'Não foi possível verificar o status do seu email. Por favor, tente novamente mais tarde.'
        });
      })
    );
  }

  // ✅ Reenviando a verificação de email
  resendVerificationEmail(): Observable<any> {
    const userEmail = localStorage.getItem(this.userKey); // Obtém o e-mail do usuário logado
    if (!userEmail) return new Observable(); // Evita erro se não houver e-mail salvo

    return this.http.post('https://characters.discloud.app/api/resend-verification', { email: userEmail }, {
      headers: { 'Content-Type': 'application/json' }
    });
  }


  // ✅ Salvar token e nome do usuário no localStorage
  private saveAuthData(token: string, userName: string) {
    localStorage.setItem(this.tokenKey, token);
    localStorage.setItem(this.userKey, userName);
  }

  // ✅ Verifica se o usuário está autenticado
  isAuthenticated(): boolean {
    return !!localStorage.getItem(this.tokenKey);
  }

  // ✅ Retorna o nome do usuário logado
  getUserName(): string {
    return localStorage.getItem(this.userKey) || 'Aventureiro';
  }

  getUserEmail(): string {
    return localStorage.getItem('user_email') || 'Email não encontrado';
  }

  // ✅ Logout (remove os dados do localStorage)
  logout() {
    localStorage.removeItem(this.tokenKey);
    localStorage.removeItem(this.userKey);
    localStorage.removeItem('user_email');
  }
}
